"use strict";

// 活跃时长统计 v3.3 (性能优化版)
// 完全适配 SillyTavern 主题变量 (磨砂/透明/自定义颜色)
// v3.3.1: 优化计时同步 + 移除旧游戏化面板

const USAGE_KEY = 'st_usage_tracker_local';
const AI_SETTINGS_KEY = 'st_usage_tracker_ai_settings_local';
const PANEL_ID = 'usage-tracker-local-panel';
const INTERVAL = 15000;
const MAX_TICK_DELTA = 60000;
const SERVER_SYNC_INTERVAL = 60000;
const RUNTIME_KEY = '__st_usage_tracker_runtime_v331';
const LEGACY_STYLE_ID = 'usage-tracker-legacy-styles';
const DASHBOARD_STYLE_ID = 'usage-tracker-analysis-styles';

const AI_MODES = {
    summary: {
        label: '总结模式',
        hint: '偏整体概览，快速抓重点',
        prompt: '更偏向整体总结，优先告诉用户这段时间最值得知道的几件事。'
    },
    insight: {
        label: '洞察模式',
        hint: '偏变化、波动和异常点',
        prompt: '更偏向洞察和观察，优先挖出变化、异常、节奏和使用模式。'
    },
    review: {
        label: '复盘模式',
        hint: '像给自己做阶段复盘',
        prompt: '更像阶段复盘，关注节奏、习惯变化和下一步可以留意的方向。'
    },
    companion: {
        label: '陪伴模式',
        hint: '语气自然一点，像陪你看数据',
        prompt: '语气更自然温和，像一个懂数据的陪伴者，但仍要基于事实说话。'
    },
    freeform: {
        label: '自由模式',
        hint: '不固定结构，自行选择重点',
        prompt: '不固定结构，自由组织表达，但要避免空话和模板腔。'
    }
};

let aiSessionState = {
    lastResult: '',
    lastSummaryText: '',
    lastMode: 'summary',
    isSending: false,
};

const trackerRuntime = window[RUNTIME_KEY] || {};
if (trackerRuntime.tickInterval) clearInterval(trackerRuntime.tickInterval);
if (trackerRuntime.panelInterval) clearInterval(trackerRuntime.panelInterval);
if (trackerRuntime.initTimeout) clearTimeout(trackerRuntime.initTimeout);
if (trackerRuntime.listeners) {
    trackerRuntime.listeners.forEach(({ target, type, handler }) => target.removeEventListener(type, handler));
}
Object.assign(trackerRuntime, {
    listeners: [],
    lastTickAt: Date.now(),
    lastServerSyncAt: trackerRuntime.lastServerSyncAt || 0,
    pendingServerData: null,
});
window[RUNTIME_KEY] = trackerRuntime;

// --- 核心：智能获取存储对象 ---
function getSTContext() {
    if (window.SillyTavern && window.SillyTavern.extensionSettings) {
        return { settings: window.SillyTavern.extensionSettings, save: window.SillyTavern.saveSettingsDebounced };
    }
    if (window.SillyTavern && typeof window.SillyTavern.getContext === 'function') {
        const ctx = window.SillyTavern.getContext();
        if (ctx.extensionSettings) { return { settings: ctx.extensionSettings, save: ctx.saveSettingsDebounced }; }
    }
    if (window.extension_settings && typeof window.saveSettingsDebounced === 'function') {
        return { settings: window.extension_settings, save: window.saveSettingsDebounced };
    }
    return null;
}

// --- 数据处理 ---
function getToday() {
    const now = new Date();
    return now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0') + '-' + String(now.getDate()).padStart(2, '0');
}

function isValidDateKey(dateKey) {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(dateKey)) return false;
    const [year, month, day] = dateKey.split('-').map(Number);
    const date = new Date(year, month - 1, day);
    return date.getFullYear() === year && date.getMonth() === month - 1 && date.getDate() === day;
}

function normalizeUsageData(rawData, strict = false) {
    if (!rawData || typeof rawData !== 'object' || Array.isArray(rawData)) {
        if (strict) throw new Error('数据必须是日期到毫秒数的对象');
        return {};
    }

    const normalized = {};
    Object.entries(rawData).forEach(([day, value]) => {
        const numericValue = Number(value);
        const isValid = isValidDateKey(day) && Number.isFinite(numericValue) && numericValue >= 0;
        if (!isValid) {
            if (strict) throw new Error(`无效记录：${day}`);
            return;
        }
        normalized[day] = Math.floor(numericValue);
    });
    return normalized;
}

function mergeUsageData(firstData, secondData) {
    const first = normalizeUsageData(firstData);
    const second = normalizeUsageData(secondData);
    const mergedData = {};
    const allDays = new Set([...Object.keys(first), ...Object.keys(second)]);
    allDays.forEach(day => {
        mergedData[day] = Math.max(first[day] || 0, second[day] || 0);
    });
    return mergedData;
}

function loadUsage() {
    let localData = {};
    let serverData = {};
    try { localData = JSON.parse(localStorage.getItem(USAGE_KEY) || '{}'); } catch (e) { console.error("Local load error:", e); }
    const ctx = getSTContext();
    if (ctx && ctx.settings && ctx.settings[USAGE_KEY]) { serverData = ctx.settings[USAGE_KEY]; }
    const mergedData = mergeUsageData(localData, serverData);
    if (JSON.stringify(mergedData) !== JSON.stringify(localData)) { localStorage.setItem(USAGE_KEY, JSON.stringify(mergedData)); }
    return mergedData;
}

function syncUsageToServer(data, force = false) {
    const ctx = getSTContext();
    if (!ctx || !ctx.save) return;

    const now = Date.now();
    if (!force && now - trackerRuntime.lastServerSyncAt < SERVER_SYNC_INTERVAL) {
        trackerRuntime.pendingServerData = data;
        return;
    }

    if (JSON.stringify(ctx.settings[USAGE_KEY]) !== JSON.stringify(data)) {
        ctx.settings[USAGE_KEY] = data;
        ctx.save();
    }
    trackerRuntime.lastServerSyncAt = now;
    trackerRuntime.pendingServerData = null;
}

function flushServerSync() {
    if (trackerRuntime.pendingServerData) {
        syncUsageToServer(trackerRuntime.pendingServerData, true);
    }
}

function saveUsage(data, options = {}) {
    const normalizedData = normalizeUsageData(data);
    const finalData = options.replace ? normalizedData : mergeUsageData(loadUsage(), normalizedData);
    localStorage.setItem(USAGE_KEY, JSON.stringify(finalData));
    syncUsageToServer(finalData, Boolean(options.forceServerSync));
    return finalData;
}

function addActiveTime(ms) {
    if (!Number.isFinite(ms) || ms <= 0) return;
    const usage = loadUsage();
    const today = getToday();
    if (!usage[today]) usage[today] = 0;
    usage[today] += Math.floor(ms);
    saveUsage(usage);
}

function msToHourMin(ms) {
    const totalMin = Math.floor(ms / 60000);
    const hours = Math.floor(totalMin / 60);
    const minutes = totalMin % 60;
    return { hours, minutes };
}

function getStats(all = false) {
    const usage = loadUsage();
    const days = Object.keys(usage).sort().reverse();
    let totalMs = 0;
    let dailyStats = [];
    let monthlyStats = {};
    days.forEach(day => {
        totalMs += usage[day];
        const month = day.substring(0, 7);
        if (!monthlyStats[month]) monthlyStats[month] = { totalMs: 0, daily: [] };
        monthlyStats[month].totalMs += usage[day];
        monthlyStats[month].daily.push({ date: day, ms: usage[day] });
        dailyStats.push({ date: day, ms: usage[day] });
    });
    const sortedMonths = Object.keys(monthlyStats).sort().reverse();
    const total = msToHourMin(totalMs);
    return { monthly: monthlyStats, sortedMonths: sortedMonths, daily: dailyStats, total: { hours: total.hours, minutes: total.minutes, days: days.length }, rawTotalMs: totalMs };
}

// --- 导出/导入 ---
function exportData() {
    const data = localStorage.getItem(USAGE_KEY);
    if (!data || data === '{}') { alert('无数据可导出'); return; }
    try {
        const uri = 'data:application/json;charset=utf-8,' + encodeURIComponent(data);
        const a = document.createElement('a');
        a.href = uri;
        const now = new Date();
        const timeStr = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}_${String(now.getHours()).padStart(2,'0')}-${String(now.getMinutes()).padStart(2,'0')}`;
        a.download = `usage-tracker-${timeStr}.json`;
        document.body.appendChild(a); a.click(); document.body.removeChild(a);
    } catch (e) { alert('导出失败: ' + e); }
}

function handleImport(event) {
    const file = event.target.files[0];
    if (!file) return;
    if (!confirm('确定导入记录吗？未包含在导入文件里的日期会保留；相同日期以导入文件为准。')) { event.target.value = ''; return; }
    const reader = new FileReader();
    reader.onload = function(e) {
        try {
            const data = normalizeUsageData(JSON.parse(e.target.result), true);
            saveUsage({ ...loadUsage(), ...data }, { replace: true, forceServerSync: true });
            alert('导入成功！已同步至服务端。');
            showPanel();
        } catch (err) { alert('导入失败: ' + err.message); } finally { event.target.value = ''; }
    };
    reader.readAsText(file);
}

// ==========================================
// Part 1: 原版列表视图 (Legacy)
// ==========================================

function showLegacyListModal() {
    const stats = getStats(true);
    let modalHtml = '';
    if (stats.sortedMonths.length) {
        stats.sortedMonths.forEach(month => {
            const { hours, minutes } = msToHourMin(stats.monthly[month].totalMs);
            modalHtml += `
                <div class='usage-tracker-month-header' data-month='${month}'>
                    <span>${month}</span>
                    <span class='month-total'>总时长: ${hours}小时${minutes}分钟</span>
                    <span class='toggle-icon'>▼</span>
                </div>
                <table class='usage-tracker-monthly-table' data-month='${month}' style='display:none; width:100%; border-collapse:collapse; margin-bottom:10px;'>
                    <thead><tr style='background:rgba(0,0,0,0.2); text-align:left;'><th>日期</th><th>时长</th></tr></thead>
                    <tbody>
            `;
            stats.monthly[month].daily.forEach(d => {
                const { hours, minutes } = msToHourMin(d.ms);
                modalHtml += `<tr style='border-bottom:1px solid var(--SmartThemeBorderColor);'><td>${d.date}</td><td>${hours}h ${minutes}m</td></tr>`;
            });
            modalHtml += `</tbody></table>`;
        });
    } else { modalHtml = `<div style='text-align:center; padding:20px;'>暂无数据</div>`; }
    
    const parentDoc = window.parent.document;
    injectLegacyStyles();
    const $modalBody = $(parentDoc).find('#usage-tracker-modal-body');
    $modalBody.html(modalHtml);
    $(parentDoc).find('#usage-tracker-modal-overlay').css('display', 'block').hide().fadeIn(200);
    
    $modalBody.find('.usage-tracker-month-header').each(function() {
        $(this).off('click').on('click', function(e) {
            e.stopPropagation();
            const month = $(this).data('month');
            $(parentDoc).find(`.usage-tracker-monthly-table[data-month='${month}']`).slideToggle(200);
        });
    });
}

function injectLegacyStyles() {
    const parentDoc = window.parent.document;
    if ($(parentDoc).find('#usage-tracker-modal-overlay').length > 0) return;
    const styles = `
        #usage-tracker-modal-overlay { position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; background-color: rgba(0,0,0,0.7); z-index: 99990; display: none; overflow-y: auto; padding: 20px; box-sizing: border-box; }
        #usage-tracker-modal-content { background-color: var(--SmartThemeBlurTintColor, rgba(44, 47, 51, 0.9)); backdrop-filter: blur(var(--SmartThemeBlurStrength, 10px)); color: var(--SmartThemeBodyColor, #fff); padding: 20px; border-radius: 10px; width: calc(100% - 40px); max-width: 500px; margin: 0 auto; position: relative; box-sizing: border-box; border: 1px solid var(--SmartThemeBorderColor); }
        .usage-tracker-month-header { cursor: pointer; display: flex; justify-content: space-between; background: rgba(0,0,0,0.2); padding: 10px; margin-top: 5px; border-radius: 5px; }
        #usage-tracker-modal-body { max-height: 60vh; overflow-y: auto; }
    `;
    $(parentDoc.head).append(`<style>${styles}</style>`);
    $(parentDoc.body).append(`<div id="usage-tracker-modal-overlay"><div id="usage-tracker-modal-content"><div style="display:flex;justify-content:space-between;margin-bottom:10px;"><h3>全部记录</h3><span id="usage-tracker-modal-close" style="cursor:pointer;font-size:24px;">&times;</span></div><div id="usage-tracker-modal-body" style="overflow-y:auto;"></div></div></div>`);
    
    const overlay = parentDoc.getElementById('usage-tracker-modal-overlay');
    const content = parentDoc.getElementById('usage-tracker-modal-content');
    const closeBtn = parentDoc.getElementById('usage-tracker-modal-close');
    
    ['mousedown', 'mouseup', 'click'].forEach(eventType => {
        overlay.addEventListener(eventType, function(e) { e.stopPropagation(); if(e.target===overlay && eventType==='click') $(overlay).fadeOut(200); }, false);
        content.addEventListener(eventType, function(e) { e.stopPropagation(); }, false);
    });
    closeBtn.addEventListener('click', function(e) { e.stopPropagation(); $(overlay).fadeOut(200); }, false);
}


// ==========================================
// Part 2: AI 分析扩展
// ==========================================

function roundNumber(value, digits = 1) {
    if (!Number.isFinite(value)) return 0;
    const factor = Math.pow(10, digits);
    return Math.round(value * factor) / factor;
}

function parseDateKey(dateKey) {
    const [year, month, day] = dateKey.split('-').map(Number);
    return new Date(year, month - 1, day);
}

function formatDateKey(date) {
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

function shiftDate(date, offset) {
    const next = new Date(date.getFullYear(), date.getMonth(), date.getDate());
    next.setDate(next.getDate() + offset);
    return next;
}

function escapeHtml(text) {
    return String(text ?? '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

function renderMarkdownToHtml(markdownText) {
    const source = String(markdownText || '').replace(/\r\n/g, '\n');
    if (!source.trim()) return '<p>等待发送...</p>';

    const codeBlocks = [];
    let html = escapeHtml(source).replace(/```([\s\S]*?)```/g, (_, code) => {
        const token = `__CODE_BLOCK_${codeBlocks.length}__`;
        codeBlocks.push(`<pre><code>${code.trim() ? code.replace(/^\n/, '') : ''}</code></pre>`);
        return token;
    });

    html = html
        .replace(/^### (.+)$/gm, '<h3>$1</h3>')
        .replace(/^## (.+)$/gm, '<h2>$1</h2>')
        .replace(/^# (.+)$/gm, '<h1>$1</h1>')
        .replace(/^\> (.+)$/gm, '<blockquote>$1</blockquote>');

    html = html.replace(/(?:^|\n)((?:[-*] .+(?:\n|$))+)/g, (_, block) => {
        const items = block.trim().split('\n').map(line => line.replace(/^[-*] /, '').trim());
        return `\n<ul>${items.map(item => `<li>${item}</li>`).join('')}</ul>\n`;
    });

    html = html.replace(/(?:^|\n)((?:\d+\. .+(?:\n|$))+)/g, (_, block) => {
        const items = block.trim().split('\n').map(line => line.replace(/^\d+\. /, '').trim());
        return `\n<ol>${items.map(item => `<li>${item}</li>`).join('')}</ol>\n`;
    });

    html = html
        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
        .replace(/(^|[^\*])\*(?!\s)(.+?)(?<!\s)\*/g, '$1<em>$2</em>')
        .replace(/`([^`]+)`/g, '<code>$1</code>')
        .replace(/\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g, '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>');

    const blocks = html.split(/\n{2,}/).map(block => block.trim()).filter(Boolean).map(block => {
        if (/^<(h1|h2|h3|ul|ol|pre|blockquote)/.test(block)) return block;
        return `<p>${block.replace(/\n/g, '<br>')}</p>`;
    });

    html = blocks.join('');
    codeBlocks.forEach((block, index) => {
        html = html.replace(`__CODE_BLOCK_${index}__`, block);
    });
    return html;
}

function loadAISettings() {
    const defaults = { baseUrl: '', apiKey: '', model: '', mode: 'summary', extraPrompt: '' };
    try {
        const parsed = JSON.parse(localStorage.getItem(AI_SETTINGS_KEY) || '{}');
        const merged = { ...defaults, ...parsed };
        if (!AI_MODES[merged.mode]) merged.mode = defaults.mode;
        return merged;
    } catch (error) {
        console.error('AI settings load error:', error);
        return defaults;
    }
}

function saveAISettings(partialSettings) {
    const nextSettings = { ...loadAISettings(), ...partialSettings };
    if (!AI_MODES[nextSettings.mode]) nextSettings.mode = 'summary';
    localStorage.setItem(AI_SETTINGS_KEY, JSON.stringify(nextSettings));
    return nextSettings;
}

function buildCalendarSeries(usageMap, endDate, days) {
    const series = [];
    for (let offset = days - 1; offset >= 0; offset--) {
        const current = shiftDate(endDate, -offset);
        const date = formatDateKey(current);
        const ms = usageMap[date] || 0;
        series.push({
            date,
            ms,
            hours: roundNumber(ms / 3600000, 2),
            day: current.getDay(),
        });
    }
    return series;
}

function summarizeSeries(series) {
    const totalHours = roundNumber(series.reduce((sum, item) => sum + item.hours, 0), 1);
    const activeSeries = series.filter(item => item.hours > 0);
    const bestDay = activeSeries.reduce((best, item) => (!best || item.hours > best.hours ? item : best), null);
    return {
        startDate: series[0] ? series[0].date : null,
        endDate: series.length ? series[series.length - 1].date : null,
        trackedDays: series.length,
        activeDays: activeSeries.length,
        totalHours,
        avgHoursPerDay: series.length ? roundNumber(totalHours / series.length, 2) : 0,
        avgHoursPerActiveDay: activeSeries.length ? roundNumber(totalHours / activeSeries.length, 2) : 0,
        activeRate: series.length ? roundNumber((activeSeries.length / series.length) * 100, 1) : 0,
        bestDay: bestDay ? { date: bestDay.date, hours: roundNumber(bestDay.hours, 1) } : null,
    };
}

function buildPeriodDiff(currentPeriod, previousPeriod) {
    const totalHoursDelta = roundNumber(currentPeriod.totalHours - previousPeriod.totalHours, 1);
    const avgHoursDelta = roundNumber(currentPeriod.avgHoursPerDay - previousPeriod.avgHoursPerDay, 2);
    return {
        totalHours: {
            current: currentPeriod.totalHours,
            previous: previousPeriod.totalHours,
            delta: totalHoursDelta,
            deltaPct: previousPeriod.totalHours ? roundNumber((totalHoursDelta / previousPeriod.totalHours) * 100, 1) : null,
        },
        activeDays: {
            current: currentPeriod.activeDays,
            previous: previousPeriod.activeDays,
            delta: currentPeriod.activeDays - previousPeriod.activeDays,
        },
        avgHoursPerDay: {
            current: currentPeriod.avgHoursPerDay,
            previous: previousPeriod.avgHoursPerDay,
            delta: avgHoursDelta,
            deltaPct: previousPeriod.avgHoursPerDay ? roundNumber((avgHoursDelta / previousPeriod.avgHoursPerDay) * 100, 1) : null,
        },
    };
}

function getCurrentStreak(usageMap, today) {
    let streak = 0;
    for (let offset = 0; offset < 3660; offset++) {
        const currentKey = formatDateKey(shiftDate(today, -offset));
        if ((usageMap[currentKey] || 0) > 0) streak++;
        else break;
    }
    return streak;
}

function getLongestStreak(activeEntries) {
    if (!activeEntries.length) return 0;
    let longest = 1;
    let streak = 1;
    for (let index = 1; index < activeEntries.length; index++) {
        const prev = activeEntries[index - 1].obj.getTime();
        const current = activeEntries[index].obj.getTime();
        if ((current - prev) / 86400000 === 1) streak++;
        else streak = 1;
        if (streak > longest) longest = streak;
    }
    return longest;
}

function buildSummaryHighlights(summary) {
    const items = [];
    const diff7 = summary.deltas.last7VsPrevious7.totalHours.deltaPct;
    const diff30 = summary.deltas.last30VsPrevious30.totalHours.deltaPct;

    if (summary.periods.last7Days.totalHours === 0) {
        items.push('最近 7 天没有记录到活跃时长。');
    } else if (diff7 !== null && Math.abs(diff7) >= 20) {
        items.push(`最近 7 天总时长较前 7 天${diff7 > 0 ? '增加' : '减少'} ${Math.abs(diff7)}%。`);
    }

    if (diff30 !== null && Math.abs(diff30) >= 15) {
        items.push(`最近 30 天整体较前 30 天${diff30 > 0 ? '更活跃' : '更收敛'}，变化约 ${Math.abs(diff30)}%。`);
    }

    if (summary.overview.currentStreakDays >= 3) {
        items.push(`当前已经连续活跃 ${summary.overview.currentStreakDays} 天。`);
    }

    if (summary.overview.bestDay) {
        items.push(`峰值日是 ${summary.overview.bestDay.date}，当天约 ${summary.overview.bestDay.hours} 小时。`);
    }

    if (summary.overview.weekendRatio >= 50) {
        items.push(`周末时长占比 ${summary.overview.weekendRatio}%，节奏偏向周末集中。`);
    }

    if (!items.length) items.push('整体数据比较平稳，近期没有特别突出的波动。');
    return items.slice(0, 5);
}

function buildUsageSummary() {
    const usageMap = loadUsage();
    const stats = getStats(true);
    const today = parseDateKey(getToday());
    const weekMap = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    const activeEntries = stats.daily.map(item => {
        const obj = parseDateKey(item.date);
        return {
            date: item.date,
            ms: item.ms,
            hours: roundNumber(item.ms / 3600000, 2),
            day: obj.getDay(),
            obj,
        };
    }).sort((a, b) => a.obj - b.obj);

    const totalHours = roundNumber(stats.rawTotalMs / 3600000, 1);
    const last7Series = buildCalendarSeries(usageMap, today, 7);
    const previous7Series = buildCalendarSeries(usageMap, shiftDate(today, -7), 7);
    const last14Series = buildCalendarSeries(usageMap, today, 14);
    const last30Series = buildCalendarSeries(usageMap, today, 30);
    const previous30Series = buildCalendarSeries(usageMap, shiftDate(today, -30), 30);
    const topDays = [...activeEntries]
        .sort((a, b) => b.hours - a.hours)
        .slice(0, 5)
        .map(item => ({ date: item.date, weekday: weekMap[item.day], hours: roundNumber(item.hours, 1) }));
    const weekendHours = roundNumber(activeEntries.filter(item => item.day === 0 || item.day === 6).reduce((sum, item) => sum + item.hours, 0), 1);
    const weekdayBreakdown = weekMap.map((weekday, dayIndex) => {
        const matches = activeEntries.filter(item => item.day === dayIndex);
        const weekdayHours = roundNumber(matches.reduce((sum, item) => sum + item.hours, 0), 1);
        return {
            weekday,
            totalHours: weekdayHours,
            activeDays: matches.length,
            avgHoursPerActiveDay: matches.length ? roundNumber(weekdayHours / matches.length, 2) : 0,
        };
    });

    const summary = {
        meta: {
            generatedAt: new Date().toISOString(),
            timezone: Intl.DateTimeFormat().resolvedOptions().timeZone || 'local',
            scriptVersion: '3.4.0-ai',
            dataPoints: activeEntries.length,
        },
        overview: {
            totalHours,
            activeDays: activeEntries.length,
            trackingStart: activeEntries[0] ? activeEntries[0].date : null,
            trackingEnd: activeEntries.length ? activeEntries[activeEntries.length - 1].date : null,
            avgHoursPerActiveDay: activeEntries.length ? roundNumber(totalHours / activeEntries.length, 2) : 0,
            currentStreakDays: getCurrentStreak(usageMap, today),
            longestStreakDays: getLongestStreak(activeEntries),
            bestDay: topDays[0] || null,
            weekendHours,
            weekendRatio: totalHours ? roundNumber((weekendHours / totalHours) * 100, 1) : 0,
        },
        periods: {
            last7Days: summarizeSeries(last7Series),
            previous7Days: summarizeSeries(previous7Series),
            last30Days: summarizeSeries(last30Series),
            previous30Days: summarizeSeries(previous30Series),
        },
        deltas: {},
        patterns: {
            weekdayBreakdown,
            topDays,
            monthlyHours: stats.sortedMonths.slice().reverse().map(month => ({
                month,
                totalHours: roundNumber(stats.monthly[month].totalMs / 3600000, 1),
                activeDays: stats.monthly[month].daily.length,
            })),
            recent14Days: last14Series.map(item => ({ date: item.date, hours: roundNumber(item.hours, 1) })),
            recent30Days: last30Series.map(item => ({ date: item.date, hours: roundNumber(item.hours, 1) })),
        },
    };

    summary.deltas = {
        last7VsPrevious7: buildPeriodDiff(summary.periods.last7Days, summary.periods.previous7Days),
        last30VsPrevious30: buildPeriodDiff(summary.periods.last30Days, summary.periods.previous30Days),
    };
    summary.highlights = buildSummaryHighlights(summary);
    return summary;
}

function buildAISystemPrompt(modeId) {
    const mode = AI_MODES[modeId] || AI_MODES.summary;
    return [
        '你是一名帮助用户理解使用时长数据的分析助手。',
        '你会收到一份本地脚本预先整理好的 JSON 摘要。',
        '请只基于 JSON 里已有的事实进行分析，不要编造原因、细节或不存在的行为。',
        '优先关注最明显的变化、异常、节奏和模式，不需要机械复述所有字段。',
        '如果变化不大，可以直接说整体平稳。',
        '允许自由组织表达，但请避免模板腔、空话和过度格式化。',
        mode.prompt,
    ].join('\n');
}

function buildAIUserPrompt(summary, modeId, extraPrompt) {
    const mode = AI_MODES[modeId] || AI_MODES.summary;
    const sections = [
        `当前分析模式：${mode.label}（${mode.hint}）`,
        '以下是使用时长统计的 JSON 摘要，请直接开始分析。',
    ];
    if (extraPrompt && extraPrompt.trim()) sections.push(`用户附加提示词：${extraPrompt.trim()}`);
    sections.push('JSON 摘要：');
    sections.push(JSON.stringify(summary, null, 2));
    return sections.join('\n\n');
}

function buildChatCompletionsUrl(baseUrl) {
    const normalized = (baseUrl || '').trim().replace(/\/+$/, '');
    if (!normalized) return '';
    return /\/chat\/completions$/i.test(normalized) ? normalized : `${normalized}/chat/completions`;
}

function buildModelsUrl(baseUrl) {
    const normalized = (baseUrl || '').trim().replace(/\/+$/, '');
    if (!normalized) return '';
    if (/\/chat\/completions$/i.test(normalized)) return normalized.replace(/\/chat\/completions$/i, '/models');
    return /\/models$/i.test(normalized) ? normalized : `${normalized}/models`;
}

function extractAIResponseText(payload) {
    const messageContent = payload?.choices?.[0]?.message?.content;
    if (typeof messageContent === 'string') return messageContent.trim();
    if (Array.isArray(messageContent)) {
        return messageContent.map(part => {
            if (typeof part === 'string') return part;
            if (typeof part?.text === 'string') return part.text;
            return '';
        }).join('\n').trim();
    }
    if (typeof payload?.choices?.[0]?.text === 'string') return payload.choices[0].text.trim();
    if (typeof payload?.output_text === 'string') return payload.output_text.trim();
    return '';
}

async function copyText(text) {
    if (!text) throw new Error('没有可复制的内容');
    if (navigator.clipboard && typeof navigator.clipboard.writeText === 'function') {
        await navigator.clipboard.writeText(text);
        return;
    }
    const textarea = document.createElement('textarea');
    textarea.value = text;
    textarea.setAttribute('readonly', 'readonly');
    textarea.style.position = 'fixed';
    textarea.style.opacity = '0';
    document.body.appendChild(textarea);
    textarea.select();
    document.execCommand('copy');
    document.body.removeChild(textarea);
}

async function requestAIAnalysis(settings, summary, modeId, extraPrompt) {
    const endpoint = buildChatCompletionsUrl(settings.baseUrl);
    if (!endpoint) throw new Error('请先填写 API Base URL');
    if (!settings.apiKey) throw new Error('请先填写 API Key');
    if (!settings.model) throw new Error('请先填写模型名称');

    const response = await fetch(endpoint, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${settings.apiKey}`,
        },
        body: JSON.stringify({
            model: settings.model,
            temperature: modeId === 'summary' ? 0.7 : 0.9,
            messages: [
                { role: 'system', content: buildAISystemPrompt(modeId) },
                { role: 'user', content: buildAIUserPrompt(summary, modeId, extraPrompt) },
            ],
        }),
    });

    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error?.message || data?.message || `请求失败 (${response.status})`);

    const text = extractAIResponseText(data);
    if (!text) throw new Error('模型没有返回可读内容');
    return text;
}

async function requestAvailableModels(settings) {
    const endpoint = buildModelsUrl(settings.baseUrl);
    if (!endpoint) throw new Error('请先填写 API Base URL');
    if (!settings.apiKey) throw new Error('请先填写 API Key');

    const response = await fetch(endpoint, {
        method: 'GET',
        headers: {
            Authorization: `Bearer ${settings.apiKey}`,
        },
    });

    const data = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(data?.error?.message || data?.message || `获取模型失败 (${response.status})`);

    const models = Array.isArray(data?.data)
        ? data.data.map(item => item?.id).filter(id => typeof id === 'string' && id.trim())
        : [];

    if (!models.length) throw new Error('接口没有返回可选模型列表');
    return models.sort((a, b) => a.localeCompare(b));
}

