function setAnalysisStatus($root, message, type = 'info') {
    const $status = $root.find('#st-ai-status');
    $status.removeClass('is-error is-success');
    if (type === 'error') $status.addClass('is-error');
    if (type === 'success') $status.addClass('is-success');
    $status.text(message);
}

function setAnalysisLoading($root, loading) {
    aiSessionState.isSending = loading;
    const $sendButton = $root.find('#st-ai-send');
    $sendButton.prop('disabled', loading);
    $sendButton.text(loading ? '分析中...' : '发送分析');
}

function getModalSettings($root) {
    return {
        baseUrl: $root.find('#st-ai-base-url').val().trim(),
        apiKey: $root.find('#st-ai-api-key').val().trim(),
        model: $root.find('#st-ai-model').val().trim(),
        mode: $root.find('.st-ai-mode-btn.active').data('mode') || 'summary',
        extraPrompt: $root.find('#st-ai-extra-prompt').val(),
    };
}

function populateModelSelect($root, models) {
    const $select = $root.find('#st-ai-model-select');
    const currentValue = $root.find('#st-ai-model').val().trim();
    const options = ['<option value="">从已获取模型中选择</option>']
        .concat(models.map(model => `<option value="${escapeHtml(model)}">${escapeHtml(model)}</option>`));
    $select.html(options.join(''));
    if (currentValue && models.includes(currentValue)) $select.val(currentValue);
    $select.show();
}

function bindAnalysisModalEvents($root) {
    const persist = () => saveAISettings(getModalSettings($root));

    $root.find('#st-ai-base-url, #st-ai-api-key, #st-ai-model').on('change blur', persist);
    $root.find('#st-ai-extra-prompt').on('input', persist);
    $root.find('#st-ai-model-select').on('change', function() {
        const model = $(this).val();
        if (!model) return;
        $root.find('#st-ai-model').val(model);
        persist();
        setAnalysisStatus($root, `已选择模型：${model}`, 'success');
    });

    $root.find('.st-ai-mode-btn').on('click', function() {
        const modeId = $(this).data('mode');
        $root.find('.st-ai-mode-btn').removeClass('active');
        $(this).addClass('active');
        $root.find('#st-ai-mode-desc').text((AI_MODES[modeId] || AI_MODES.summary).hint);
        saveAISettings({ mode: modeId });
    });

    $root.find('#st-ai-fetch-models').on('click', async function() {
        const settings = saveAISettings(getModalSettings($root));
        const $button = $(this);
        if ($button.prop('disabled')) return;
        try {
            $button.prop('disabled', true).text('获取中...');
            setAnalysisStatus($root, '正在获取模型列表...');
            const models = await requestAvailableModels(settings);
            populateModelSelect($root, models);
            setAnalysisStatus($root, `已获取 ${models.length} 个模型。`, 'success');
        } catch (error) {
            console.error('Fetch models error:', error);
            setAnalysisStatus($root, `获取模型失败：${error.message}`, 'error');
        } finally {
            $button.prop('disabled', false).text('获取模型');
        }
    });

    $root.find('#st-ai-toggle-summary').on('click', function() {
        const $preview = $root.find('#st-ai-summary-preview');
        const isVisible = $preview.is(':visible');
        $preview.toggle(!isVisible);
        $(this).text(isVisible ? '查看 JSON 摘要' : '隐藏 JSON 摘要');
    });

    $root.find('#st-ai-copy-summary').on('click', async function() {
        try {
            await copyText(aiSessionState.lastSummaryText);
            setAnalysisStatus($root, 'JSON 摘要已复制。', 'success');
        } catch (error) {
            setAnalysisStatus($root, `复制摘要失败：${error.message}`, 'error');
        }
    });

    $root.find('#st-ai-copy-result').on('click', async function() {
        try {
            await copyText(aiSessionState.lastResult);
            setAnalysisStatus($root, '分析结果已复制。', 'success');
        } catch (error) {
            setAnalysisStatus($root, `复制结果失败：${error.message}`, 'error');
        }
    });

    $root.find('#st-ai-send').on('click', async function() {
        if (aiSessionState.isSending) return;
        const settings = saveAISettings(getModalSettings($root));
        const summary = buildUsageSummary();
        const summaryText = JSON.stringify(summary, null, 2);
        aiSessionState.lastSummaryText = summaryText;
        aiSessionState.lastMode = settings.mode;
        $root.find('#st-ai-summary-preview').text(summaryText);

        try {
            setAnalysisLoading($root, true);
            setAnalysisStatus($root, `正在以“${(AI_MODES[settings.mode] || AI_MODES.summary).label}”发送分析请求...`);
            const result = await requestAIAnalysis(settings, summary, settings.mode, settings.extraPrompt);
            aiSessionState.lastResult = result;
            $root.find('#st-ai-result').html(renderMarkdownToHtml(result));
            setAnalysisStatus($root, '分析完成。', 'success');
        } catch (error) {
            console.error('AI analysis error:', error);
            setAnalysisStatus($root, `分析失败：${error.message}`, 'error');
        } finally {
            setAnalysisLoading($root, false);
        }
    });
}

