function renderPanel() {
    const stats = getStats();
    let html = `
    <div id="${PANEL_ID}-container">
        <div class="inline-drawer">
            <div class="inline-drawer-toggle inline-drawer-header">
                <b style="color: var(--SmartThemeBodyColor);">活跃时长统计</b>
                <div class="inline-drawer-icon fa-solid fa-circle-chevron-down"></div>
            </div>
            <div class="inline-drawer-content" style="padding: 15px;">
                <div style='display: flex; gap: 5px; margin-bottom: 10px; flex-wrap: wrap;'>
<button id='usage-tracker-local-dashboard' class='menu_button' style='flex: 1; padding: 5px;'>AI分析</button>
                    <button id='usage-tracker-local-view-all' class='menu_button' style='flex: 1; padding: 5px;'>查看全部</button>
                    <button id='usage-tracker-local-import' class='menu_button' style='flex: 1; padding: 5px;'>导入</button>
                    <button id='usage-tracker-local-export' class='menu_button' style='flex: 1; padding: 5px;'>导出</button>
                    <button id='usage-tracker-local-reset' class='menu_button' style='flex: 1; padding: 5px;'>清空</button>
                    <input type='file' id='usage-tracker-local-file-input' accept='.json' style='display:none;'>
                </div>
                <table style='width:100%; margin-bottom:10px;'>
                    <thead><tr><th>日期</th><th>时长</th></tr></thead>
                    <tbody>`;
    const dailyStats = stats.daily.slice(0, 3);
    if (dailyStats.length) {
        dailyStats.forEach(d => {
            const { hours, minutes } = msToHourMin(d.ms);
            html += `<tr><td>${d.date}</td><td>${hours}小时${minutes}分钟</td></tr>`;
        });
    } else { html += `<tr><td colspan='2' style='text-align:center;'>暂无数据</td></tr>`; }
    
    const ctx = getSTContext();
    const syncStatus = ctx 
        ? '<span style="color:#90ee90; font-size:0.8em;">● 已连接服务端</span>' 
        : '<span style="color:#ff6b6b; font-size:0.8em;" title="未检测到 SillyTavern 对象">● 仅本地模式(未连接)</span>';
    
    html += `</tbody></table>
                <div style='font-size:0.9em;'>
                    累计: <b>${stats.total.hours}</b>小时<b>${stats.total.minutes}</b>分 / ${stats.total.days}天<br>
                    状态: ${syncStatus}
                </div>
            </div>
        </div>
    </div>`;
    return html;
}

function showPanel() {
    const parentDoc = window.parent.document;
    // 注入两种模态框的样式
    injectLegacyStyles();
    injectAnalysisStyles();
    
    let $panelContainer = $(parentDoc).find(`#${PANEL_ID}`);
    if ($panelContainer.length === 0) {
        const $extSettings = $(parentDoc).find('#extensions_settings');
        if ($extSettings.length) { $extSettings.append(`<div id='${PANEL_ID}'></div>`); $panelContainer = $(parentDoc).find(`#${PANEL_ID}`); }
    }
    if ($panelContainer.length) {
        $panelContainer.html(renderPanel());
        const $panel = $panelContainer.find(`#${PANEL_ID}-container`);
        $panel.find('#usage-tracker-local-reset').on('click', function() { 
            if (confirm('确定清空所有数据吗？')) { 
                localStorage.removeItem(USAGE_KEY); 
                trackerRuntime.pendingServerData = null;
                const ctx = getSTContext();
                if(ctx) {
                    delete ctx.settings[USAGE_KEY];
                    ctx.save();
                    trackerRuntime.lastServerSyncAt = Date.now();
                }
                showPanel(); 
            } 
        });
        $panel.find('#usage-tracker-local-export').on('click', exportData);
        const $fileInput = $panel.find('#usage-tracker-local-file-input');
        $panel.find('#usage-tracker-local-import').on('click', () => { $fileInput.click(); });
        $fileInput.on('change', handleImport);
        
        // 绑定两个按钮
        $panel.find('#usage-tracker-local-view-all').on('click', showLegacyListModal);
        $panel.find('#usage-tracker-local-dashboard').on('click', showAnalysisModal);
    }
}

// --- 初始化与轮询 ---
let active = isTrackerActive();

function isTrackerActive() {
    return document.visibilityState !== 'hidden' && document.hasFocus();
}

function registerRuntimeListener(target, type, handler) {
    target.addEventListener(type, handler);
    trackerRuntime.listeners.push({ target, type, handler });
}

function updateActiveState() {
    active = isTrackerActive();
    trackerRuntime.lastTickAt = Date.now();
    if (!active) flushServerSync();
}

function tick() {
    const now = Date.now();
    const elapsed = now - trackerRuntime.lastTickAt;
    trackerRuntime.lastTickAt = now;
    active = isTrackerActive();
    if (!active) return;

    const delta = Math.min(elapsed, MAX_TICK_DELTA);
    if (delta > 0) addActiveTime(delta);
}

trackerRuntime.tickInterval = setInterval(tick, INTERVAL);
registerRuntimeListener(window, 'focus', updateActiveState);
registerRuntimeListener(window, 'blur', updateActiveState);
registerRuntimeListener(document, 'visibilitychange', updateActiveState);
registerRuntimeListener(window, 'pagehide', flushServerSync);
registerRuntimeListener(window, 'beforeunload', flushServerSync);

let initAttempts = 0;
function initSmart() {
    if (getSTContext()) { showPanel(); } 
    else {
        initAttempts++;
        if (initAttempts < 30) trackerRuntime.initTimeout = setTimeout(initSmart, 500);
        else showPanel(); 
    }
}
initSmart();
trackerRuntime.panelInterval = setInterval(showPanel, 60000);
